package main

import (
	"fmt"
	"os/exec"
)

func runCommand(cmd string, args ...string) error {
	command := exec.Command(cmd, args...)
	output, err := command.CombinedOutput()
	if err != nil {
		fmt.Printf("Error running %s: %s\n", cmd, err)
		fmt.Println(string(output))
		return err
	}
	fmt.Println(string(output))
	return nil
}

